class MyMotor
{
    int MaxRPM = 3000;
    public int CalcSpeed(int rpm) { return rpm; }
    public int CalcSpeed(double percent)
    {
        return (int)(MaxRPM * percent / 100.0);
    }
}

var m = new MyMotor();
int s1 = m.CalcSpeed(1500);
int s2 = m.CalcSpeed(50.0);
Print($"转速1: {s1} RPM");
Print($"转速2: {s2} RPM");
